};

//-------------------------------------------------------------------------
// 삭제 f_Delete
//------------------------------------------------------------------------- 
scwin.btn_Delete_onclick = async function (e) {

    if (ds_certidetail.getTotalRow() == 0){
        await $c.win.alert($c.data.getMessage(MSG_CM_WRN_004, "DATA"));
        return;			
    }
    if (ed_certiNo.getValue() == ""){
        await $c.win.alert($c.data.getMessage(MSG_CM_WRN_004, "CERTI-NO"));
        return;			        
    }
    if(scwin.pgmId == "fs_202_04_01b.jsp" && scwin.ed_ediSndDt != ""){
        if(! await $c.win.confirm(scwin.MSG_FS_WRN_018)){
            return;
        } else {
            ds_certicommon.setCellData(0, "certiNo", ed_certiNo.getValue());
            scwin.delflag = "DEL";
            $c.sbm.execute(sbm_certi_save);

        }        
    } else {
        if(! await $c.win.confirm(MSG_CM_CRM_004)){
            return;
        } else {
            ds_certicommon.setCellData(0, "certiNo", ed_certiNo.getValue());

            scwin.delflag = "DEL";

            $c.sbm.execute(sbm_certi_save);

        }
    }

};

